const l=JSON.parse('{"key":"v-27b65b48","path":"/project/rbac%E6%9D%83%E9%99%90%E6%8E%A7%E5%88%B6%E7%9A%84%E5%AE%9E%E7%8E%B0.html","title":"rbac权限控制的实现","lang":"zh-CN","frontmatter":{"title":"rbac权限控制的实现","isTimeLine":true,"date":"2026-01-17T00:00:00.000Z","category":["前端"],"tag":["JavaScript","Vue"]},"headers":[{"level":3,"title":"场景","slug":"场景","link":"#场景","children":[]},{"level":3,"title":"解决方案：RBAC","slug":"解决方案-rbac","link":"#解决方案-rbac","children":[]},{"level":3,"title":"难点","slug":"难点","link":"#难点","children":[]},{"level":3,"title":"路由权限实现","slug":"路由权限实现","link":"#路由权限实现","children":[]},{"level":3,"title":"按钮权限实现","slug":"按钮权限实现","link":"#按钮权限实现","children":[]}],"git":{"createdTime":1773458982000,"updatedTime":1773506313000,"contributors":[{"name":"liunal","email":"liunal","commits":2}]},"readingTime":{"minutes":5.63,"words":1690},"filePathRelative":"project/rbac权限控制的实现.md","localizedDate":"2026年1月17日","excerpt":"<h3> 场景</h3>\\n<ol>\\n<li>不同账号需要展示不同的菜单；比如分析人员可以看到分析相关仪器、试剂，看不到报告管理相关菜单。</li>\\n<li>还有一种是是页面中的某些功能，比如是业务员可以申请核销发票，没有审批按钮，而财务有这种功能权限。</li>\\n</ol>\\n<h3> 解决方案：RBAC</h3>\\n<ol>\\n<li>传统的权限设计是对每个人进行单独的权限设置，但这种方式已经不适合目前企业的高效管控权限的发展需求。</li>\\n<li>RBAC（<code>Role-Based Access Control</code>）基于角色的权限分配解决方法，它是在人与权限之前加一个角色的中间层，想对某个用户设置权限，就对该用户设置对应的角色就可。</li>\\n<li>就是做角色与权限的映射关系，为角色分配权限。</li>\\n</ol>"}');export{l as data};
